import{_ as t,c as o,o as s,ag as n}from"./chunks/framework.DVUBUV_u.js";const u=JSON.parse('{"title":"Параметры обновления","description":"","frontmatter":{"title":"Параметры обновления"},"headers":[],"relativePath":"ru/options/update_settings.md","filePath":"ru/options/update_settings.md"}'),e={name:"ru/options/update_settings.md"};function a(g,r,h,i,p,l){return s(),o("div",null,[...r[0]||(r[0]=[n('<h1 id="параметры-обновления" tabindex="-1">Параметры обновления <a class="header-anchor" href="#параметры-обновления" aria-label="Permalink to &quot;Параметры обновления&quot;">​</a></h1><p>В <strong>Options → General</strong> ниже блока визуальных настроек <strong>Customize</strong> расположены два связанных с данными блока: <strong>Search Parameters</strong> (параметры поиска) и <strong>Auto Refresh</strong> (автообновление дерева и сторов). Они сохраняются в общем профиле настроек вместе с остальными опциями (см. <a href="/docs/ru/options/settings_management.html">Менеджер настроек</a>).</p><hr><h2 id="search-parameters" tabindex="-1">Search Parameters <a class="header-anchor" href="#search-parameters" aria-label="Permalink to &quot;Search Parameters&quot;">​</a></h2><p>Здесь задаются <strong>глобальные</strong> правила для <strong>текстового поиска и фильтрации</strong> во вкладках, где используется единый набор параметров (в первую очередь <strong>Props</strong>, <strong>Network</strong>, <strong>Pinia</strong> — поля поиска и фасетные фильтры опираются на те же <code>debounce</code> и <code>minLength</code>).</p><h3 id="search-debounce-ms" tabindex="-1">Search Debounce (ms) <a class="header-anchor" href="#search-debounce-ms" aria-label="Permalink to &quot;Search Debounce (ms)&quot;">​</a></h3><p><strong>Задержка перед применением строки поиска</strong> после того, как вы перестали печатать. Пока таймер не истёк, запрос к фильтру не «дребезжит» на каждый символ: снижается нагрузка и лишнее мерцание списков.</p><p>В интерфейсе допустимы значения примерно <strong>от 100 до 1000</strong> миллисекунд (типичное по умолчанию — около <strong>300</strong>). Меньше задержка — быстрее реакция, но больше пересчётов; больше — спокойнее для тяжёлых таблиц.</p><h3 id="minimum-search-length" tabindex="-1">Minimum Search Length <a class="header-anchor" href="#minimum-search-length" aria-label="Permalink to &quot;Minimum Search Length&quot;">​</a></h3><p><strong>Минимальная длина строки</strong>, с которой поиск начинает <strong>фильтровать</strong> данные. Если в поле меньше символов, чем это число, фильтр ведёт себя как «пустой запрос» (обычно показывается полный список, пока вы не наберёте достаточно букв).</p><p>Допустимый диапазон в форме — <strong>от 1 до 10</strong> символов (частое значение по умолчанию — <strong>2</strong>). Значение <strong>1</strong> позволяет реагировать уже на один символ; <strong>больше</strong> — удобно, когда короткие префиксы дают слишком широкий и шумный результат.</p><p>Эти два параметра <strong>общие для всех модулей</strong>, которые их читают: не нужно отдельно настраивать Debounce в Network и в Props — меняется одна пара полей в Options.</p><hr><h2 id="auto-refresh" tabindex="-1">Auto Refresh <a class="header-anchor" href="#auto-refresh" aria-label="Permalink to &quot;Auto Refresh&quot;">​</a></h2><p>Переключатель <strong>Enable auto refresh</strong> включает <strong>периодическое обновление данных</strong> в части вкладок инспектора, где отображается <strong>дерево компонентов</strong> и связанные с ним списки, а также <strong>таблица Pinia Store</strong>. Интервал задаётся полем <strong>Refresh Interval</strong> (в секундах: <strong>1, 2, 5, 10, 30</strong>).</p><p>Пока автообновление включено, инспектор <strong>повторно запрашивает</strong> актуальное состояние с страницы через выбранный интервал, <strong>если в этот момент не идёт другая загрузка</strong> (очередные тики не наслаиваются друг на друга).</p><h3 id="видимость-панели" tabindex="-1">Видимость панели <a class="header-anchor" href="#видимость-панели" aria-label="Permalink to &quot;Видимость панели&quot;">​</a></h3><p><strong>Автообновление</strong> опрашивает страницу по интервалу <strong>только пока панель инспектора видна</strong> (сценарий внедрённого UI считается активным). При <strong>скрытии</strong> панели (свёрнутая или неотображаемая область DevTools / оверлея) <strong>интервалы останавливаются</strong>; после <strong>возврата</strong> панели на экран опрос <strong>возобновляется</strong> — если переключатель <strong>Enable auto refresh</strong> по-прежнему включён.</p><p>Это относится к вкладкам, которые используют этот механизм: в первую очередь <strong>Props</strong> и <strong>Stores</strong>.</p><h3 id="защита-от-«шторма»-обновлении-props" tabindex="-1">Защита от «шторма» обновлений (Props) <a class="header-anchor" href="#защита-от-«шторма»-обновлении-props" aria-label="Permalink to &quot;Защита от «шторма» обновлений (Props)&quot;">​</a></h3><p>На вкладке <strong>Props</strong>, помимо интервала из <strong>Refresh Interval</strong>, данные дерева компонентов могут приходить с страницы <strong>очень часто</strong> (динамическое приложение, каскад перерисовок). Если за короткий промежуток времени приходит слишком много подряд снимков дерева, срабатывает <strong>встроенная защита от перегрузки</strong>: на ограниченное время <strong>приостанавливается применение</strong> очередных снимков к таблице, чтобы не перегружать интерфейс. Отдельной настройки этого поведения в форме <strong>Options</strong> нет — это защитный слой канала дерева.</p><p><strong>Вкладка Network</strong> в список автообновляемых по <strong>Auto Refresh</strong> <strong>не входит</strong>: перехват и таблица запросов живут по своей логике потока событий страницы.</p><p>Используйте Auto Refresh, если приложение <strong>часто меняет</strong> дерево компонентов или состав сторов без перезагрузки страницы, и вы хотите видеть картину <strong>без ручного нажатия Refresh</strong> на каждом изменении. На очень коротком интервале при большом дереве возможна заметная нагрузка — при необходимости увеличьте шаг до <strong>10–30</strong> секунд.</p><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/ru/options/settings_management.html">Менеджер настроек</a></li><li><a href="/docs/ru/options/display_mode.html">Режимы отображения</a></li></ul>',26)])])}const d=t(e,[["render",a]]);export{u as __pageData,d as default};
